+    }
+
+    private static List<string> SplitIntoSentences(string text)
+    {
+        return text
+            .Split(['.', '!', '?'], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
+            .Where(s => s.Length > 0)
+            .Select(s => s + ".")
+            .ToList();
+    }
+
+    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
+    {
+        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+        char[] separators = [' ', ',', ';', ':', '"', '\'', '(', ')', '-', '\n', '\r', '\t'];
+
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in sentence.Split(separators, StringSplitOptions.RemoveEmptyEntries))
+            {
+                var normalized = word.TrimEnd('.');
+                if (normalized.Length <= 2) continue; // skip short/stop words
+
+                if (!frequencies.TryAdd(normalized, 1))
+                    frequencies[normalized]++;
+            }
+        }
+
+        return frequencies;
+    }
+
+    private static List<(string Sentence, int Index, double Score)> ScoreSentences(
+        List<string> sentences, Dictionary<string, int> wordFrequencies)
+    {
+        char[] separators = [' ', ',', ';', ':', '"', '\'', '(', ')', '-', '\n', '\r', '\t'];
+        var scored = new List<(string Sentence, int Index, double Score)>();
+
+        for (int i = 0; i < sentences.Count; i++)
+        {
+            var words = sentences[i].Split(separators, StringSplitOptions.RemoveEmptyEntries);
+            double score = 0;
+
+            foreach (var word in words)
+            {
+                var normalized = word.TrimEnd('.');
+                if (wordFrequencies.TryGetValue(normalized, out int freq))
+                    score += freq;
+            }
+
+            // Normalize by sentence length to avoid bias toward longer sentences
+            if (words.Length > 0)
+                score /= words.Length;
+
+            scored.Add((sentences[i], i, score));
+        }
+
+        return scored;
+    }
+}
